import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';

const StudentDashboard = () => {
  const [info, setInfo] = useState({});
  const [error, setError] = useState('');
  const token = localStorage.getItem('accessToken');
  const navigate = useNavigate();

  useEffect(() => {
    if (!token) {
      navigate('/login');
      return;
    }

    fetch('http://localhost:8000/api/student-info/', {
      headers: { Authorization: `Bearer ${token}` }
    })
      .then(res => res.json())
      .then(data => setInfo(data))
      .catch(() => setError('Failed to fetch student info.'));
  }, []);

  return (
    <div style={{ padding: '2rem' }}>
      <h2>Student Dashboard</h2>
      {error && <p style={{ color: 'red' }}>{error}</p>}
      <p><strong>Username:</strong> {info.username}</p>
      <p><strong>Email:</strong> {info.email}</p>
      <p><strong>Class:</strong> {info.classroom}</p>
      <p><strong>Subjects:</strong> {info.subjects?.join(', ')}</p>
    </div>
  );
};

export default StudentDashboard;
